// Run Once for All Items ✅
const fs = require('fs');

// Récupérer TOUS les items
const data = $input.all().map(item => item.json);

// Écrire le tableau complet
fs.writeFileSync(
  'C:\\hicham\\scripts\\match_article_br\\input_temp.json',
  JSON.stringify(data, null, 2),
  'utf-8'
);

// Retourner tous les items pour la suite du workflow
return $input.all();

// Mode: Run Once for All Items
const items = $input.all();
const results = [];

for (const item of items) {
  const stdout = item.json.stdout;

  if (!stdout || stdout.trim() === '') {
    results.push({ json: { error: "stdout vide", raw: item.json } });
    continue;
  }

  let parsed;
  try {
    parsed = JSON.parse(stdout);
  } catch (e) {
    results.push({ json: { error: "JSON parse error: " + e.message, raw: stdout.slice(0, 300) } });
    continue;
  }

  // Normalise en tableau
  const lines = Array.isArray(parsed) ? parsed : [parsed];

  for (const line of lines) {
    results.push({ json: line });
  }
}

return results;

parameters.inputSchema:
{
  "type": "object",
  "properties": {

    "type_document": {
      "type": "string",
      "description": "Type du document détecté : 'BON_DE_LIVRAISON'. Valeur fixe pour ce workflow"
    },

    "numero_bl": {
      "type": "string",
      "description": "Numéro du bon de livraison. Ex: '0040355464'. Si plusieurs BL dans le même PDF, les séparer par virgule"
    },

    "date_bl": {
      "type": "string",
      "description": "Date du BL au format tel que détecté dans le document (ex: 04/07/2024)"
    },

    "numero_bc": {
      "type": "string",
      "description": "Numéro(s) du bon de commande. Chercher les mots-clés : 'BON DE COMMANDE', 'V/Commande', 'BC N°', 'N° BC'. Si plusieurs BCs, les séparer par ' - ' (ex: BC191397 - BC192493). Chaîne vide si aucun BC trouvé"
    },

    "fournisseur_nom": {
      "type": "string",
      "description": "Nom ou raison sociale du fournisseur émetteur du BL"
    },

    "base_ht": {
      "type": "number",
      "description": "Total HT du document. Format marocain : le point '.' est séparateur de milliers, la virgule ',' est séparateur décimal. Convertir en nombre JSON standard (ex: '34.453,94' → 34453.94)"
    },

    "tva_montant": {
      "type": "number",
      "description": "Montant total de la TVA. Même règle de conversion format marocain que base_ht. Ex: '6.890,79' → 6890.79. null si absent"
    },

    "total_ttc": {
      "type": "number",
      "description": "Total TTC du document. Même règle de conversion format marocain que base_ht. null si absent"
    },

    "lignes": {
      "type": "array",
      "description": "Toutes les lignes articles du tableau. Obligatoire : ne jamais retourner un tableau vide si des articles sont visibles. Extraire TOUTES les lignes. Le nombre de lignes = nombre de valeurs dans la colonne Quantité",
      "items": {
        "type": "object",
        "properties": {

          "reference": {
            "type": "string",
            "description": "Code ou référence article tel qu'affiché dans la colonne REF / Référence / Code. null si absent"
          },

          "designation": {
            "type": "string",
            "description": "Libellé de l'article sans accents, apostrophes ni caractères non-ASCII (é→e, à→a, ç→c, '→espace). RÈGLE CRITIQUE : le nombre de désignations distinctes = nombre de valeurs dans la colonne Quantité. Si la colonne Désignation a exactement N fragments séparés par saut de ligne et Quantité = N valeurs → chaque fragment est une désignation SÉPARÉE, ne pas les fusionner. Si fragments Désignation > N → tout concaténer en une seule désignation"
          },

          "quantite": {
            "type": "number",
            "description": "Quantité numérique de la ligne. JAMAIS une date. Ne jamais concaténer deux valeurs séparées par saut de ligne (ex: '69\\n16' → ligne 1 qty=69, ligne 2 qty=16). Si pu_ht × quantite ≠ montant_ht affiché, recalculer : quantite = montant_ht / pu_ht"
          },

          "pu_ht": {
            "type": "number",
            "description": "Prix unitaire HT de la ligne. Même règle de conversion format marocain (point=milliers, virgule=décimal). null si absent"
          },

          "remise_pct": {
            "type": "number",
            "description": "Remise en pourcentage appliquée à la ligne. Mettre 0 si aucune remise mentionnée"
          },

          "montant_ht": {
            "type": "number",
            "description": "Montant HT de la ligne. Même règle de conversion format marocain. Vérification : pu_ht × quantite × (1 - remise_pct/100) doit correspondre. null si absent"
          }
        }
      }
    }
  }
}

